const { SQS, APIGatewayManagementApi } = require("@aws-sdk/client-lambda");
const AWS = require("aws-sdk");
const dotenv = require("dotenv");

// Load environment variables from .env file
dotenv.config();

const sqs = new SQS({ region: process.env.AWS_REGION });
const api = new APIGatewayManagementApi({ region: process.env.AWS_REGION });
const dynamodb = new AWS.DynamoDB.DocumentClient({ region: process.env.AWS_REGION });

exports.handler = async (event) => {
  const promises = event.Records.map(async (record) => {
    try {
      const order = JSON.parse(record.body);

      // Call external payment API and update DynamoDB with the result (replace with actual API calls)
      const paymentResponse = await api.callApi({
        restOptions: {
          path: process.env.PAYMENT_API_URL,
          method: 'POST',
          body: JSON.stringify(order),
        },
      }).promise();

      // Update DynamoDB (replace with actual update code)
      await dynamodb.put({
        TableName: process.env.DYNAMODB_TABLE_NAME,
        Item: {
          id: order.id,
          paymentStatus: 'processed',
          // Add other fields as needed
        },
      }).promise();
    } catch (error) {
      console.error(`Error processing order ${record.message}:`, error);
    }
  });

  await Promise.all(promises);
};